1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const BASE_PREMIUM: Record<string, number> = { sword: 100, staff: 80 };
4	const DEFAULT_BASE_PREMIUM = 60;
5	
6	export function quote(policy: { items: { type: string }[]; customer: { yearsWithMHPCO: number }; isFollowUp: boolean }) {
7	  if (policy.items.length === 0) {
8	    return { premium: PROCESSING_FEE };
9	  }
10	  const basePremium = BASE_PREMIUM[policy.items[0].type] ?? DEFAULT_BASE_PREMIUM;
11	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
12	  return { premium: basePremium + firstInsuranceSurcharge + PROCESSING_FEE };
13	}
14	
15	export function claim() {
16	  return undefined;
17	}
